import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatWithCommentMarkerTest {

    @Test
    void testWithCommentMarkerValidChar() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character commentMarker = '#';
        CSVFormat newFormat = format.withCommentMarker(commentMarker);
        assertNotNull(newFormat);
        assertEquals(commentMarker, newFormat.getCommentMarker());
        // Original format unchanged
        assertNull(format.getCommentMarker());
    }

    @Test
    void testWithCommentMarkerNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withCommentMarker(null);
        assertNotNull(newFormat);
        assertNull(newFormat.getCommentMarker());
    }

    @Test
    void testWithCommentMarkerLineBreakCharThrows() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character[] lineBreaks = {'\n', '\r'};
        for (Character lb : lineBreaks) {
            IllegalArgumentException ex = assertThrows(IllegalArgumentException.class,
                    () -> format.withCommentMarker(lb));
            assertEquals("The comment start marker character cannot be a line break", ex.getMessage());
        }
    }
}
